import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, Marker, ZoomControl, Popup } from "react-leaflet";
import L from "leaflet";
import 'leaflet/dist/leaflet.css';
import BusTrendChart from "./BusTrendChart";

// Define colored icons
const greenIcon = new L.Icon({
  iconUrl: 'https://chart.googleapis.com/chart?chst=d_map_pin_letter&chld=%E2%80%A2|00FF00',
  iconSize: [25, 41],
  iconAnchor: [12, 41],
  popupAnchor: [1, -34],
  shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
  shadowSize: [41, 41]
});

const redIcon = new L.Icon({
  iconUrl: 'https://chart.googleapis.com/chart?chst=d_map_pin_letter&chld=%E2%80%A2|FF0000',
  iconSize: [25, 41],
  iconAnchor: [12, 41],
  popupAnchor: [1, -34],
  shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
  shadowSize: [41, 41]
});

const orangeIcon = new L.Icon({
  iconUrl: 'https://chart.googleapis.com/chart?chst=d_map_pin_letter&chld=%E2%80%A2|FFA500',
  iconSize: [25, 41],
  iconAnchor: [12, 41],
  popupAnchor: [1, -34],
  shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
  shadowSize: [41, 41]
});

const MapComponent = () => {
  const [buses, setBuses] = useState([]);
  const [showChart, setShowChart] = useState(false);

  useEffect(() => {
    const fetchBuses = async () => {
      try {
        const response = await fetch("http://localhost:8000/buses");
        const data = await response.json();
        const now = Math.floor(Date.now() / 1000);

        const processed = data.map(bus => {
          let status = "normal";

          // Ghost detection: no update for 2 minutes
          if (bus.timestamp && now - bus.timestamp > 120) status = "ghost";

          // Anomaly detection: outside NYC bounds
          if (bus.lat < 40.5 || bus.lat > 41 || bus.lon < -74.5 || bus.lon > -73) status = "anomaly";

          return { ...bus, status };
        });

        setBuses(processed);
      } catch (err) {
        console.error("Error fetching bus data:", err);
      }
    };

    fetchBuses();
    const interval = setInterval(fetchBuses, 2 * 60 * 1000); // fetch every 2 minutes
    return () => clearInterval(interval);
  }, []);

  // Count buses by status
  const counts = {
    normal: buses.filter(b => b.status === "normal").length,
    ghost: buses.filter(b => b.status === "ghost").length,
    anomaly: buses.filter(b => b.status === "anomaly").length
  };

  return (
    <div>
      <MapContainer
        center={[40.7128, -74.0060]}
        zoom={11}
        style={{ height: "100vh", width: "100vw" }}
        zoomControl={false} // move to left
      >
        <TileLayer
          url="https://tiles.stadiamaps.com/tiles/alidade_smooth_light/{z}/{x}/{y}{r}.png"
          attribution='&copy; <a href="https://stadiamaps.com/">Stadia Maps</a>'
        />

        <ZoomControl position="topleft" />

        {buses.map((bus, index) => {
          const icon = bus.status === "ghost" ? redIcon : bus.status === "anomaly" ? orangeIcon : greenIcon;
          return (
            <Marker
              key={`${bus.id}-${index}`}
              position={[bus.lat, bus.lon]}
              icon={icon}
            >
              <Popup>
                <strong>{bus.id}</strong><br />
                Status: {bus.status}<br />
                Last Update: {bus.timestamp ? new Date(bus.timestamp * 1000).toLocaleTimeString() : "N/A"}
              </Popup>
            </Marker>
          );
        })}
      </MapContainer>

      {/* Bottom-left counter */}
      <div style={{
        position: "absolute",
        bottom: 10,
        left: 10,
        backgroundColor: "rgba(255,255,255,0.9)",
        padding: "10px",
        borderRadius: "8px",
        fontWeight: "bold"
      }}>
        Normal: {counts.normal} | Ghost: {counts.ghost} | Anomaly: {counts.anomaly}
      </div>

      {/* Chart toggle button */}
      <button
        onClick={() => setShowChart(!showChart)}
        style={{
          position: "absolute",
          top: 10,
          left: 10,
          zIndex: 1000,
          padding: "10px 15px",
          borderRadius: "5px",
          border: "none",
          backgroundColor: "#333",
          color: "white",
          cursor: "pointer"
        }}
      >
        {showChart ? "Hide Chart" : "Show Chart"}
      </button>

      {showChart && <BusTrendChart buses={buses} />}
    </div>
  );
};

export default MapComponent;
